import pymongo
from bson.code import Code

def get_db_connection(host='localhost', port=27017, db_name='advanced_filter_db'):
    """Establishes a connection to MongoDB and returns the database object."""
    client = pymongo.MongoClient(host, port)
    return client[db_name]

def create_sample_data(db):
    """Inserts sample data into the collection if it's empty."""
    collection = db.user_data
    if collection.count_documents({}) == 0:
        print("Inserting sample data...")
        sample_users = [
            {"name": "Alice", "age": 30, "city": "New York", "score": 85, "tags": ["premium", "active"]},
            {"name": "Bob", "age": 24, "city": "Los Angeles", "score": 92, "tags": ["active"]},
            {"name": "Charlie", "age": 35, "city": "New York", "score": 78, "tags": ["inactive"]},
            {"name": "David", "age": 29, "city": "Chicago", "score": 95, "tags": ["premium", "active"]},
            {"name": "Eve", "age": 40, "city": "Los Angeles", "score": 88, "tags": ["active"]},
            {"name": "Frank", "age": 22, "city": "Houston", "score": 70, "tags": ["inactive"]},
        ]
        collection.insert_many(sample_users)
        print("Sample data inserted.")
    else:
        print("Sample data already exists.")

def query_with_where(collection, js_filter_expression):
    """
    Executes a MongoDB query using the $where operator with a server-side JavaScript expression.

    Args:
        collection: The PyMongo collection object.
        js_filter_expression: A string containing the JavaScript expression to be executed
                              on the server for filtering documents.
                              Example: "this.age > 30 && this.city == 'New York'"
                                       "this.score > 90 || this.name.startsWith('D')"
                                       "this.tags.includes('premium')"
    Returns:
        A list of dictionaries representing the matching documents.
    """
    try:
        # Using bson.code.Code to ensure the JavaScript is treated as code.
        # This is generally safer and clearer than just passing a string directly.
        query = {"$where": Code(js_filter_expression)}
        results = list(collection.find(query))
        return results
    except pymongo.errors.OperationFailure as e:
        print(f"MongoDB Operation Failure: {e}")
        print("Please check your JavaScript expression for syntax errors or invalid operations.")
        return []
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return []

def main():
    db = get_db_connection()
    collection = db.user_data
    create_sample_data(db)

    print("\n--- Advanced Data Filtering Service ---")
    print("Enter JavaScript expressions to filter documents.")
    print("Use 'this.' to refer to document fields. Examples:")
    print("  this.age > 30 && this.city == 'New York'")
    print("  this.score > 90 || this.name.startsWith('D')")
    print("  this.tags.includes('premium')")
    print("  this.name.length > 5 && this.age < 35")
    print("  exit to quit")

    while True:
        js_input = input("\nEnter JavaScript filter expression: ").strip()
        if js_input.lower() == 'exit':
            break

        if not js_input:
            print("Expression cannot be empty. Please try again.")
            continue

        print(f"\nExecuting query with $where: '{js_input}'")
        filtered_documents = query_with_where(collection, js_input)

        if filtered_documents:
            print(f"\nFound {len(filtered_documents)} matching documents:")
            for doc in filtered_documents:
                print(doc)
        else:
            print("\nNo documents matched the expression or an error occurred.")

    print("\nExiting Advanced Data Filtering Service. Goodbye!")
    db.client.close()

if __name__ == "__main__":
    main()